class Solution:
    def earliestAndLatest(self, n: int, firstPlayer: int, secondPlayer: int) -> List[int]:
        def dfs(state):
            key = tuple(state)
            if key in memo:
                return memo[key]
            if firstPlayer in state and secondPlayer in state:
                idx1 = state.index(firstPlayer)
                idx2 = state.index(secondPlayer)
                if idx1 + idx2 == len(state) - 1:
                    return (1, 1)
            min_round = float('inf')
            max_round = 0
            m = len(state)
            half = (m + 1) // 2
            for mask in range(1 << half):
                nxt = []
                for i in range(half):
                    left = state[i]
                    right = state[m - 1 - i]
                    if i == m - 1 - i:
                        nxt.append(left)
                    else:
                        if (mask >> i) & 1:
                            chosen = left
                        else:
                            chosen = right
                        if chosen == firstPlayer or chosen == secondPlayer:
                            chosen = left if left in (firstPlayer, secondPlayer) else right
                        nxt.append(chosen)
                nxt_sorted = sorted(nxt)
                if firstPlayer not in nxt_sorted or secondPlayer not in nxt_sorted:
                    continue
                a, b = dfs(nxt_sorted)
                min_round = min(min_round, a + 1)
                max_round = max(max_round, b + 1)
            memo[key] = (min_round, max_round)
            return (min_round, max_round)

        initial = list(range(1, n + 1))
        memo = {}
        earliest, latest = dfs(initial)
        return [earliest, latest]
